// Curated drug master seed for Indian hospitals. ~500 entries covering:
//   1. NLEM 2022 essentials (~384 drugs — covers all primary care, most
//      hospital care, most paediatrics & maternal health).
//   2. Common India-branded Rx the doctor reaches for daily (vitamins,
//      PPIs, antihypertensives, antidiabetics, antibiotics, NSAIDs,
//      analgesics, biologics in oncology, common cardiac drugs).
//   3. OTC pharmacy items (paracetamol brands, antacids, cough syrups).
//
// Sourced from public CDSCO + NLEM 2022 + IPC monographs. For a full
// production refresh, download the latest CDSCO "List of Approved Drugs"
// CSV and run scripts/importDrugMaster.ts.
//
// `brandNames` arrays are illustrative (the top 3-5 brands by volume per
// generic — not exhaustive). India has hundreds of brands per generic;
// no system tries to list them all.

export interface DrugMasterSeed {
  genericName: string;
  brandNames?: string[];
  therapeuticClass: string;
  atcCode?: string;
  strength?: string;
  form?: string;
  schedule?: string; // H / H1 / X / G / K / '' = OTC
  isEssential?: boolean;
  hsnCode?: string;
  pregnancyCategory?: string;
  indications?: string;
  contraindications?: string;
  source?: string;
}

